//! Wrap a PNG file as [`PleromaticFrame`] (`image_encoding=png`) and write bincode for `aeon-monitor`.
//!
//! Usage:
//! ```text
//! png-embed-frame INPUT.png [OUTPUT.frame]
//! ```
//! Default output: `monitor_image.frame` in cwd.

use distributed_inference::pleromatic_frame::PleromaticFrame;

fn main() -> Result<(), String> {
    let mut args = std::env::args().skip(1);
    let input = args.next().ok_or_else(|| {
        "png-embed-frame INPUT.png [OUTPUT.frame]\n\
         Embeds PNG file bytes in a PleromaticFrame for aeon-monitor (AEON_MONITOR_IMAGE_FRAME)."
            .to_string()
    })?;
    let output = args
        .next()
        .unwrap_or_else(|| "monitor_image.frame".to_string());

    let bytes = std::fs::read(&input).map_err(|e| e.to_string())?;
    let label = std::path::Path::new(&input)
        .file_name()
        .and_then(|s| s.to_str())
        .unwrap_or("png")
        .to_string();
    let frame = PleromaticFrame::png_image_embedded(label, bytes);
    let blob = bincode::serialize(&frame).map_err(|e| e.to_string())?;
    std::fs::write(&output, blob).map_err(|e| e.to_string())?;
    Ok(())
}
